func NewCacheCommand(apiLogPath string) *Command {
	return &Command{
		Name:        "cache",
		Description: "Last 5 API calls with cache breakdown",
		Category:    "observability",
		Execute: func(ctx context.Context, args string) (string, error) {
			entries := readAPILog(apiLogPath)
			if len(entries) == 0 {
				return "No API calls logged yet.", nil
			}

			// Take last 5
			start := 0
			if len(entries) > 5 {
				start = len(entries) - 5
			}
			recent := entries[start:]

			// Compute average hit rate across recent entries
			var totalCacheRead, totalInput int
			for _, e := range recent {
				totalCacheRead += e.CacheRead
				totalInput += e.Input + e.CacheRead + e.CacheWrite
			}
			avgHit := 0.0
			if totalInput > 0 {
				avgHit = float64(totalCacheRead) / float64(totalInput) * 100
			}

			// [... formatted table output with Time, Input, CacheRead, CacheWrite, Cost, Hit% columns ...]
		},
	}
}
```

**How it works:**
1. Reads the API log from `apiLogPath` 
2. Returns a message if no calls logged yet
3. Takes the **last 5 entries** only
4. Calculates average cache hit rate across those 5 calls
5. Formats a table with columns: Time, Input, CacheRead, CacheWrite, Cost, Hit%
6. **Currently does NOT take any arguments** — the `args` parameter is not used

