// NewLogCommand returns a /log command showing recent event log lines.
func NewLogCommand(eventLogPath string) *Command {
	return &Command{
		Name:        "log",
		Description: "Recent event log lines",
		Category:    "diagnostics",
		Execute: func(ctx context.Context, args string) (string, error) {
			n := 20  // default
			if args != "" {
				if parsed, err := strconv.Atoi(args); err == nil && parsed > 0 {
					n = parsed
				}
			}
			result, err := tailFile(eventLogPath, n)
			// ...
		},
	}
}
```

#### Pattern 2: Integer with Named Options (/cost)
**File:** `/home/rich/git/foci/command/builtins.go` (lines 349-570)

**Examples:**
- `/cost today` — today's costs
- `/cost 24h` — last 24 hours
- `/cost week` — 7-day summary
- `/cost 3` — last 3 days (numeric argument)

